// Created: 2026-05-18

/**
 * Regression test for the codegen drift gate (M141-2 step 1, #1864).
 *
 * The drift gate is what prevents `events.generated.ts` from silently
 * diverging from `spec/hook-events.spec.yml`. If someone edits the
 * generated file directly (or the spec changes but codegen wasn't run),
 * `codegen --check` must exit non-zero so the prebuild hook + CI fail
 * fast.
 *
 * This test exercises both directions:
 *   1. On committed (clean) state, --check exits 0
 *   2. After artificially mutating the generated file, --check exits non-zero
 *
 * Always restores the original file in a finally block — leaving a stale
 * .generated.ts on disk would mask real drift in later test runs.
 */

import { describe, it, expect } from 'vitest';
import { spawnSync } from 'node:child_process';
import { readFileSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = fileURLToPath(new URL('.', import.meta.url));
const PKG_DIR = join(__dirname, '..');
const CODEGEN_SCRIPT = join(PKG_DIR, 'scripts', 'codegen.mjs');
const GENERATED_FILE = join(PKG_DIR, 'src', 'events.generated.ts');

function runCheck() {
  return spawnSync('node', [CODEGEN_SCRIPT, '--check'], {
    cwd: PKG_DIR,
    encoding: 'utf8',
  });
}

describe('codegen drift gate (#1864)', () => {
  it('exits 0 on clean committed state', () => {
    const r = runCheck();
    expect(r.status, `stderr: ${r.stderr}`).toBe(0);
    expect(r.stdout).toMatch(/match spec/);
  });

  it('exits non-zero when events.generated.ts is mutated out-of-band', () => {
    const original = readFileSync(GENERATED_FILE, 'utf8');
    try {
      // Inject a fake event that isn't in the spec — should trigger drift.
      const mutated = original.replace(
        /'ConfigChange',\n\] as const;/,
        "'ConfigChange',\n  'FakeUntrackedEvent',\n] as const;",
      );
      expect(mutated).not.toBe(original); // sanity: replacement actually happened
      writeFileSync(GENERATED_FILE, mutated, 'utf8');

      const r = runCheck();
      expect(r.status).not.toBe(0);
      expect(r.stderr).toMatch(/drift|FAILED/i);
    } finally {
      // ALWAYS restore — a stale generated file would mask real drift in
      // every subsequent test run on this machine.
      writeFileSync(GENERATED_FILE, original, 'utf8');
    }
  });

  it('restoration in the prior test was correct (sanity follow-up)', () => {
    // If the previous test's finally block ran, --check should pass again.
    const r = runCheck();
    expect(r.status, `stderr: ${r.stderr}`).toBe(0);
  });
});
